11	#[Layout('layouts.app')]
12	class CampaignApprovalQueue extends Component
13	{
14	    protected ApiClient $apiClient;
15	
16	    public bool $showRejectModal = false;
17	    public string $rejectReason = '';
18	    public ?int $rejectItemId = null;
19	    public ?string $rejectItemType = null;
20	
21	    public function boot(ApiClient $apiClient): void
22	    {
23	        $this->apiClient = $apiClient;
24	    }
25	
26	    public function approveCampaign(int $campaignId): void
27	    {
28	        try {
29	            $this->apiClient->post("/api/campaigns/{$campaignId}/approve");
30	            session()->flash('success', 'Campaign approved.');
31	        } catch (RuntimeException $e) {
32	            session()->flash('error', $e->getMessage());
33	        }
34	    }
35	
36	    public function approveProgram(int $programId): void
37	    {
38	        try {
39	            $this->apiClient->post("/api/programs/{$programId}/approve");
40	            session()->flash('success', 'Program approved.');
41	        } catch (RuntimeException $e) {
42	            session()->flash('error', $e->getMessage());
43	        }
44	    }
45	
46	    public function openRejectModal(int $itemId, string $itemType): void
47	    {
48	        $this->rejectItemId = $itemId;
49	        $this->rejectItemType = $itemType;
50	        $this->rejectReason = '';
51	        $this->showRejectModal = true;
52	    }
53	
54	    public function closeRejectModal(): void
55	    {
56	        $this->showRejectModal = false;
57	        $this->rejectItemId = null;
58	        $this->rejectItemType = null;
59	        $this->rejectReason = '';
60	    }
61	
62	    public function confirmReject(): void
63	    {
64	        if (trim($this->rejectReason) === '') {
65	            $this->addError('rejectReason', 'A rejection reason is required.');
66	            return;
67	        }
68	
69	        try {
70	            if ($this->rejectItemType === 'campaign') {
71	                $this->apiClient->post("/api/campaigns/{$this->rejectItemId}/reject", [
72	                    'notes' => $this->rejectReason,
73	                ]);
74	                session()->flash('success', 'Campaign rejected.');
75	            } elseif ($this->rejectItemType === 'program') {
76	                // Programs don't have a dedicated reject endpoint; use visibility toggle to offline
77	                // or a specific endpoint if available. For now, use a POST to the program's visibility.
78	                $this->apiClient->post("/api/programs/{$this->rejectItemId}/visibility", [
79	                    'visibility' => 'offline',
80	                ]);
81	                session()->flash('success', 'Program rejected.');
82	            }
83	        } catch (RuntimeException $e) {
84	            session()->flash('error', $e->getMessage());
85	        }
86	
87	        $this->closeRejectModal();
88	    }
89	
90	    public function render(): View
91	    {
92	        $items = collect();
93	
94	        // Fetch pending campaigns (status=pending_review)
95	        try {
96	            $campaignResponse = $this->apiClient->get('/api/campaigns', [
97	                'status' => 'pending_review',
98	                'per_page' => 50,
99	            ]);
100	            $pendingCampaigns = collect($campaignResponse['data'] ?? [])
101	                ->map(function ($campaign) {
102	                    return [
103	                        'id' => $campaign['id'],
104	                        'type' => 'campaign',
105	                        'title' => $campaign['title'],
106	                        'creator' => $campaign['creator']['display_name']
107	                            ?? $campaign['creator']['username']
108	                            ?? 'Unknown',
109	                        'submitted_at' => $campaign['updated_at'] ?? $campaign['created_at'],
110	                    ];
111	                });
112	            $items = $items->merge($pendingCampaigns);
113	        } catch (RuntimeException $e) {
114	            // Campaigns may not be accessible
115	        }
116	
117	        // Fetch pending programs (status=pending_review)
118	        try {
119	            $programResponse = $this->apiClient->get('/api/programs', [
120	                'status' => 'pending_review',
121	                'per_page' => 50,
122	            ]);
123	            $pendingPrograms = collect($programResponse['data'] ?? [])
124	                ->map(function ($program) {
125	                    return [
126	                        'id' => $program['id'],
127	                        'type' => 'program',
128	                        'title' => $program['title'],
129	                        'creator' => $program['creator']['display_name']
130	                            ?? $program['creator']['username']
131	                            ?? 'Unknown',
132	                        'submitted_at' => $program['updated_at'] ?? $program['created_at'],
133	                    ];
134	                });
135	            $items = $items->merge($pendingPrograms);
136	        } catch (RuntimeException $e) {
137	            // Programs may not be accessible
138	        }
139	
140	        $items = $items->sortBy('submitted_at')->values();
141	
142	        return view('livewire.campaign.campaign-approval-queue', [
143	            'items' => $items,
144	        ]);
145	    }
146	}
