5	use App\Http\Controllers\Api\BaseController;
6	use App\Models\DeviceFingerprint;
7	use App\Models\User;
8	use App\Services\Auth\AuthenticationService;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	use Illuminate\Support\Facades\Hash;
12	
13	class AuthController extends BaseController
14	{
15	    public function __construct(
16	        private readonly AuthenticationService $authenticationService,
17	    ) {}
18	
19	    public function login(Request $request): JsonResponse
20	    {
21	        $request->validate([
22	            'username' => 'required|string',
23	            'password' => 'required|string',
24	        ]);
25	
26	        $username = $request->input('username');
27	        $password = $request->input('password');
28	
29	        if ($this->authenticationService->isLockedOut($username)) {
30	            return $this->error('Account is temporarily locked due to too many failed attempts.', 423);
31	        }
32	
33	        $user = User::where('username', $username)->first();
34	
35	        if (! $user || ! Hash::check($password, $user->password)) {
36	            $this->authenticationService->recordFailedAttempt($username, $request->ip() ?? '0.0.0.0');
37	            return $this->error('Invalid credentials.', 401);
38	        }
39	
40	        // Delete old tokens for this user
41	        $user->tokens()->delete();
42	
43	        // Create a new Sanctum token
44	        $token = $user->createToken('api-token')->plainTextToken;
45	
46	        // Record device fingerprint if provided
47	        if ($request->filled('fingerprint_hash')) {
48	            DeviceFingerprint::updateOrCreate(
49	                [
50	                    'user_id' => $user->id,
51	                    'fingerprint_hash' => $request->input('fingerprint_hash'),
52	                ],
53	                [
54	                    'fingerprint_encrypted' => $request->input('fingerprint_hash'),
55	                    'ip_address_encrypted' => $request->ip(),
56	                    'user_agent' => $request->userAgent(),
57	                    'last_seen_at' => now(),
58	                ],
59	            );
60	        }
61	
62	        $user->load('roles');
63	
64	        return $this->success([
65	            'user' => $user,
66	            'token' => $token,
67	        ]);
68	    }
69	
70	    public function logout(Request $request): JsonResponse
71	    {
72	        $request->user()->currentAccessToken()->delete();
73	
74	        return $this->success(['message' => 'Logged out successfully.']);
75	    }
76	
77	    public function me(Request $request): JsonResponse
78	    {
79	        $user = $request->user();
80	
81	        if (! $user) {
82	            return $this->error('Unauthenticated.', 401);
83	        }
84	
85	        $user->load('roles');
86	
87	        return $this->success($user);
88	    }
89	}
