12	class AfterSalesController extends BaseController
13	{
14	    /**
15	     * POST /api/orders/{order}/after-sales
16	     */
17	    public function store(Request $request, Order $order): JsonResponse
18	    {
19	        $this->authorize('submitAfterSales', $order);
20	
21	        if ($order->status->value !== 'fulfilled') {
22	            return $this->error('After-sales requests can only be submitted for fulfilled orders.', 409);
23	        }
24	
25	        if ($order->has_pending_refund) {
26	            return $this->error('Cannot submit after-sales request while a refund is pending.', 409);
27	        }
28	
29	        $request->validate([
30	            'type' => 'required|string|in:refund,exchange,complaint,other',
31	            'reason' => 'required|string|max:2000',
32	            'attachment' => 'required|file|max:10240|mimes:jpg,jpeg,png,pdf,doc,docx',
33	        ]);
34	
35	        $data = [
36	            'order_id' => $order->id,
37	            'user_id' => $request->user()->id,
38	            'type' => $request->input('type'),
39	            'reason' => $request->input('reason'),
40	            'status' => AfterSalesStatus::Submitted,
41	        ];
42	
43	        if ($request->hasFile('attachment')) {
44	            $file = $request->file('attachment');
45	            $path = $file->store('after-sales', 'local');
46	
47	            $data['attachment_path'] = $path;
48	            $data['attachment_mime'] = $file->getMimeType();
49	            $data['attachment_checksum'] = hash_file('sha256', $file->getRealPath());
50	            $data['attachment_size'] = $file->getSize();
51	        }
52	
53	        $afterSales = AfterSalesRequest::create($data);
54	
55	        $order->update(['has_pending_after_sales' => true]);
56	
57	        return $this->success($afterSales, 201);
58	    }
59	
60	    /**
61	     * POST /api/after-sales/{afterSalesRequest}/review
62	     */
63	    public function review(Request $request, AfterSalesRequest $afterSalesRequest): JsonResponse
64	    {
65	        $this->authorize('review', $afterSalesRequest);
66	
67	        if ($afterSalesRequest->status !== AfterSalesStatus::Submitted) {
68	            return $this->error('Only submitted requests can be moved to review.', 422);
69	        }
70	
71	        $request->validate([
72	            'staff_notes' => 'required|string|max:2000',
73	        ]);
74	
75	        $afterSalesRequest->update([
76	            'status' => AfterSalesStatus::UnderReview,
77	            'staff_notes' => $request->input('staff_notes'),
78	        ]);
79	
80	        return $this->success($afterSalesRequest->refresh());
81	    }
82	
83	    /**
84	     * POST /api/after-sales/{afterSalesRequest}/resolve
85	     */
86	    public function resolve(Request $request, AfterSalesRequest $afterSalesRequest): JsonResponse
87	    {
88	        $this->authorize('resolve', $afterSalesRequest);
89	
90	        if ($afterSalesRequest->status !== AfterSalesStatus::UnderReview) {
91	            return $this->error('Only requests under review can be resolved.', 422);
92	        }
93	
94	        $request->validate([
95	            'status' => 'required|string|in:approved,rejected',
96	            'staff_notes' => 'required|string|max:2000',
97	        ]);
98	
99	        $afterSalesRequest->update([
100	            'status' => AfterSalesStatus::from($request->input('status')),
101	            'staff_notes' => $request->input('staff_notes'),
102	            'resolved_at' => now(),
103	            'resolved_by' => $request->user()->id,
104	        ]);
105	
106	        $afterSalesRequest->order->update(['has_pending_after_sales' => false]);
107	
108	        return $this->success($afterSalesRequest->refresh());
109	    }
