24	    public function login(Request $request): RedirectResponse
25	    {
26	        $request->validate([
27	            'username' => 'required|string',
28	            'password' => 'required|string',
29	        ]);
30	
31	        try {
32	            $response = $this->apiClient->login(
33	                $request->input('username'),
34	                $request->input('password'),
35	            );
36	        } catch (RuntimeException $e) {
37	            return back()->withErrors(['username' => 'Invalid credentials.'])->withInput(['username' => $request->input('username')]);
38	        }
39	
40	        $data = $response['data'] ?? $response;
41	        $token = $data['token'] ?? ($response['token'] ?? null);
42	        $user = $data['user'] ?? ($response['user'] ?? $data);
43	
44	        /** @var SessionGuard $guard */
45	        $guard = auth()->guard('web');
46	        $guard->login($user, $token);
47	
48	        $request->session()->regenerate();
49	
50	        return redirect()->intended(route('dashboard'));
51	    }
