3	namespace App\Services\Campaign;
4	
5	use App\Enums\CampaignStatus;
6	use App\Events\CampaignApproved;
7	use App\Events\CampaignFailed;
8	use App\Events\CampaignRejected;
9	use App\Models\Campaign;
10	use App\Models\User;
11	use RuntimeException;
12	
13	class CampaignLifecycleService
14	{
15	    public function submitForReview(Campaign $campaign): Campaign
16	    {
17	        if ($campaign->status !== CampaignStatus::Draft) {
18	            throw new RuntimeException('Only draft campaigns can be submitted for review.');
19	        }
20	
21	        $campaign->update([
22	            'status' => CampaignStatus::PendingReview,
23	        ]);
24	
25	        return $campaign->refresh();
26	    }
27	
28	    public function approve(Campaign $campaign, User $moderator, ?string $notes = null): Campaign
29	    {
30	        if ($campaign->status !== CampaignStatus::PendingReview) {
31	            throw new RuntimeException('Only campaigns pending review can be approved.');
32	        }
33	
34	        $campaign->update([
35	            'status' => CampaignStatus::Fundraising,
36	            'reviewed_by' => $moderator->id,
37	            'reviewed_at' => now(),
38	            'review_notes' => $notes,
39	        ]);
40	
41	        $campaign->refresh();
42	
43	        CampaignApproved::dispatch($campaign, $moderator);
44	
45	        return $campaign;
46	    }
47	
48	    public function reject(Campaign $campaign, User $moderator, string $notes): Campaign
49	    {
50	        if ($campaign->status !== CampaignStatus::PendingReview) {
51	            throw new RuntimeException('Only campaigns pending review can be rejected.');
52	        }
53	
54	        $campaign->update([
55	            'status' => CampaignStatus::Draft,
56	            'reviewed_by' => $moderator->id,
57	            'reviewed_at' => now(),
58	            'review_notes' => $notes,
59	        ]);
60	
61	        $campaign->refresh();
62	
63	        CampaignRejected::dispatch($campaign, $moderator, $notes);
64	
65	        return $campaign;
66	    }
67	
68	    public function publish(Campaign $campaign): Campaign
69	    {
70	        if ($campaign->status !== CampaignStatus::Fundraising) {
71	            throw new RuntimeException('Only approved campaigns can be published.');
72	        }
73	
74	        $campaign->update([
75	            'starts_at' => now(),
76	            'ends_at' => now()->addDays($campaign->duration_days ?? 30),
77	        ]);
78	
79	        return $campaign->refresh();
80	    }
81	
82	    public function close(Campaign $campaign, User $moderator, ?string $notes = null): Campaign
83	    {
84	        $closeable = [CampaignStatus::Success, CampaignStatus::Failure, CampaignStatus::Fundraising];
85	
86	        if (! in_array($campaign->status, $closeable, true)) {
87	            throw new RuntimeException('Only fundraising, successful, or failed campaigns can be closed.');
88	        }
89	
90	        $campaign->update([
91	            'status' => CampaignStatus::Closed,
92	            'reviewed_by' => $moderator->id,
93	            'reviewed_at' => now(),
94	            'review_notes' => $notes,
95	        ]);
96	
97	        return $campaign->refresh();
98	    }
99	
100	    public function transitionExpired(): int
101	    {
102	        $expired = Campaign::query()
103	            ->where('status', CampaignStatus::Fundraising)
104	            ->whereNotNull('ends_at')
105	            ->where('ends_at', '<=', now())
106	            ->get();
107	
108	        $count = 0;
109	
110	        foreach ($expired as $campaign) {
111	            if ($campaign->pledged_amount >= $campaign->target_amount) {
112	                $campaign->update(['status' => CampaignStatus::Success]);
113	            } else {
114	                $campaign->update(['status' => CampaignStatus::Failure]);
115	                CampaignFailed::dispatch($campaign);
116	            }
117	
118	            $count++;
119	        }
120	
121	        return $count;
122	    }
123	}
