35	        $body = $this->renderTemplate($template->body_template, $data, $timezone);
36	
37	        $retentionDays = (int) (BusinessParameter::where('key', 'notification_retention_days')->first()?->getTypedValue() ?? 90);
38	
39	        return Notification::create([
40	            'id' => (string) Str::uuid(),
41	            'user_id' => $recipient->id,
42	            'template_id' => $template->id,
