39	    {
40	        try {
41	            $response = $this->apiClient->get("/api/time-slots/{$this->timeSlotId}");
42	
43	            $this->timeSlot = $response['time_slot'] ?? [];
44	            $this->availableSeats = $response['available_seats'] ?? 0;
45	            $this->totalCapacity = $this->timeSlot['seat_capacity'] ?? 0;
46	            $this->seatsBooked = $this->timeSlot['seats_booked'] ?? 0;
47	
48	            $locks = $response['locks'] ?? [];
49	
50	            // Calculate locks by others and check for my lock
51	            $this->lockedByOthers = 0;
52	            $foundMyLock = false;
53	
54	            foreach ($locks as $lock) {
55	                if (!empty($lock['held_by_me'])) {
56	                    $this->myLock = [
57	                        'id' => $lock['id'],
58	                        'quantity' => $lock['quantity'],
59	                        'locked_until' => $lock['locked_until'],
60	                    ];
61	                    $foundMyLock = true;
62	                } elseif (!empty($lock['held_by_other'])) {
63	                    $this->lockedByOthers += $lock['quantity'];
64	                }
65	            }
66	
67	            // If we had a lock but it's no longer in the active list, clear it
68	            if ($this->myLock && !$foundMyLock) {
69	                $this->myLock = null;
70	            }
71	        } catch (RuntimeException $e) {
72	            $this->errorMessage = $e->getMessage();
73	        }
