5	use App\Enums\DisputeStatus;
6	use App\Http\Controllers\Api\BaseController;
7	use App\Models\Dispute;
8	use App\Models\DisputeDecision;
9	use App\Models\Order;
10	use Illuminate\Http\JsonResponse;
11	use Illuminate\Http\Request;
12	
13	class DisputeController extends BaseController
14	{
15	    /**
16	     * GET /api/disputes
17	     */
18	    public function index(Request $request): JsonResponse
19	    {
20	        $user = $request->user();
21	
22	        $query = Dispute::query()->with(['order', 'initiator', 'arbitrator']);
23	
24	        // Moderators and admins see all disputes; regular users see only their own.
25	        if (! $user->hasRole('moderator') && ! $user->hasRole('admin')) {
26	            $query->where('initiated_by', $user->id);
27	        }
28	
29	        return $this->paginated($query->latest());
30	    }
31	
32	    /**
33	     * GET /api/disputes/{dispute}
34	     */
35	    public function show(Request $request, Dispute $dispute): JsonResponse
36	    {
37	        $user = $request->user();
38	
39	        // Regular users can only view their own disputes
40	        if (! $user->hasRole('moderator') && ! $user->hasRole('admin') && $dispute->initiated_by !== $user->id) {
41	            return $this->error('Forbidden.', 403);
42	        }
43	
44	        $dispute->load(['order', 'initiator', 'arbitrator', 'decisions']);
45	
46	        return $this->success($dispute);
47	    }
48	
49	    /**
50	     * POST /api/orders/{order}/disputes
51	     */
52	    public function store(Request $request, Order $order): JsonResponse
53	    {
54	        $this->authorize('create', [Dispute::class, $order]);
55	
56	        $request->validate([
57	            'reason' => 'required|string|max:2000',
58	        ]);
59	
60	        $dispute = Dispute::create([
61	            'order_id' => $order->id,
62	            'initiated_by' => $request->user()->id,
63	            'against_user_id' => $order->campaign?->creator_id,
64	            'status' => DisputeStatus::Open,
65	            'reason' => $request->input('reason'),
66	        ]);
67	
68	        return $this->success($dispute, 201);
69	    }
70	
71	    /**
72	     * POST /api/disputes/{dispute}/assign
73	     */
74	    public function assign(Request $request, Dispute $dispute): JsonResponse
75	    {
76	        $this->authorize('assign', $dispute);
77	
78	        $request->validate([
79	            'assigned_to' => 'required|integer|exists:users,id',
80	        ]);
81	
82	        $dispute->update([
83	            'assigned_to' => $request->input('assigned_to'),
84	            'assigned_at' => now(),
85	            'status' => DisputeStatus::UnderReview,
86	        ]);
87	
88	        return $this->success($dispute->refresh());
89	    }
90	
91	    /**
92	     * POST /api/disputes/{dispute}/decide
93	     */
94	    public function decide(Request $request, Dispute $dispute): JsonResponse
95	    {
96	        $this->authorize('decide', $dispute);
97	
98	        $request->validate([
99	            'decision' => 'required|string|max:2000',
100	            'reasoning' => 'required|string|max:5000',
101	            'action_taken' => 'sometimes|string|max:2000',
102	        ]);
103	
104	        $decision = DisputeDecision::create([
105	            'dispute_id' => $dispute->id,
106	            'decided_by' => $request->user()->id,
107	            'decision' => $request->input('decision'),
108	            'reasoning' => $request->input('reasoning'),
109	            'action_taken' => $request->input('action_taken'),
110	        ]);
111	
112	        $dispute->update([
113	            'status' => DisputeStatus::Resolved,
114	            'resolved_at' => now(),
115	        ]);
116	
117	        \App\Events\DisputeDecided::dispatch($dispute, $decision);
118	
119	        return $this->success([
120	            'dispute' => $dispute->refresh(),
121	            'decision' => $decision,
122	        ]);
123	    }
124	}
