3	namespace App\Policies;
4	
5	use App\Models\Dispute;
6	use App\Models\Order;
7	use App\Models\User;
8	
9	class DisputePolicy
10	{
11	    /**
12	     * Any authenticated user may list disputes.
13	     */
14	    public function viewAny(User $user): bool
15	    {
16	        return true;
17	    }
18	
19	    /**
20	     * The initiator, the respondent, or anyone who can arbitrate may view.
21	     */
22	    public function view(User $user, Dispute $dispute): bool
23	    {
24	        return $user->id === $dispute->initiated_by
25	            || $user->id === $dispute->against_user_id
26	            || $user->hasPermission('disputes.arbitrate');
27	    }
28	
29	    /**
30	     * Users with disputes.create may open a dispute.
31	     */
32	    public function create(User $user, Order $order): bool
33	    {
34	        return $user->hasPermission('disputes.create')
35	            && $user->id === $order->user_id;
36	    }
37	
38	    /**
39	     * Users with disputes.arbitrate may assign an arbitrator.
40	     */
41	    public function assign(User $user, Dispute $dispute): bool
42	    {
43	        return $user->hasPermission('disputes.arbitrate');
44	    }
45	
46	    /**
47	     * Only the assigned arbitrator who holds disputes.arbitrate may decide.
48	     */
49	    public function decide(User $user, Dispute $dispute): bool
50	    {
51	        return $user->hasPermission('disputes.arbitrate')
52	            && $user->id === $dispute->assigned_to;
53	    }
54	}
