3	namespace App\Http\Middleware;
4	
5	use Closure;
6	use Illuminate\Http\JsonResponse;
7	use Illuminate\Http\Request;
8	use Illuminate\Support\Facades\Cache;
9	use Symfony\Component\HttpFoundation\Response;
10	
11	class IdempotencyGuard
12	{
13	    private const CACHE_PREFIX = 'idempotency:';
14	
15	    private const CACHE_TTL_MINUTES = 10;
16	
17	    public function handle(Request $request, Closure $next): Response
18	    {
19	        $idempotencyKey = $request->header('X-Idempotency-Key');
20	
21	        if (! $idempotencyKey) {
22	            return $next($request);
23	        }
24	
25	        $userId = $request->user()?->id ?? 'anonymous';
26	        $cacheKey = self::CACHE_PREFIX . $userId . ':' . $request->method() . ':' . $request->path() . ':' . $idempotencyKey;
27	
28	        $cached = Cache::get($cacheKey);
29	
30	        if ($cached !== null) {
31	            return new JsonResponse(
32	                $cached['data'],
33	                $cached['status'],
34	                array_merge($cached['headers'] ?? [], ['X-Idempotent-Replayed' => 'true']),
35	            );
36	        }
37	
38	        /** @var Response $response */
39	        $response = $next($request);
40	
41	        if ($response instanceof JsonResponse) {
42	            Cache::put($cacheKey, [
43	                'data' => $response->getData(true),
44	                'status' => $response->getStatusCode(),
45	                'headers' => [],
46	            ], now()->addMinutes(self::CACHE_TTL_MINUTES));
47	        }
48	
49	        return $response;
50	    }
51	}
