12	class ReviewService
13	{
14	    private const VISIBILITY_DELAY_HOURS = 72;
15	
16	    public function submit(Order $order, User $reviewer, array $data): Review
17	    {
18	        if ($order->status !== OrderStatus::Fulfilled) {
19	            throw new RuntimeException('Reviews can only be submitted for fulfilled orders.');
20	        }
21	
22	        // Determine reviewee based on the review side
23	        $side = $data['side'] ?? 'user_to_creator';
24	        if ($side === 'user_to_creator') {
25	            $revieweeId = $order->campaign?->creator_id ?? $order->user_id;
26	        } else {
27	            $revieweeId = $order->user_id;
28	        }
29	
30	        $review = Review::create(array_merge($data, [
31	            'order_id' => $order->id,
32	            'reviewer_id' => $reviewer->id,
33	            'reviewee_id' => $revieweeId,
34	            'public_alias' => $this->generatePublicAlias($reviewer),
35	            'visible_after' => now()->addHours($this->getVisibilityDelayHours()),
36	            'is_visible' => false,
37	        ]));
38	
39	        ReviewSubmitted::dispatch($review);
40	
41	        return $review;
42	    }
43	
44	    public function publishPendingReviews(): int
45	    {
46	        return Review::query()
47	            ->where('is_visible', false)
48	            ->whereNotNull('visible_after')
49	            ->where('visible_after', '<=', now())
50	            ->update(['is_visible' => true]);
51	    }
