53	    private function getVisibilityDelayHours(): int
54	    {
55	        $param = \App\Models\BusinessParameter::where('key', 'review_visibility_delay_hours')->first();
56	        return $param ? (int) $param->getTypedValue() : 72;
57	    }
58	
59	    private function generatePublicAlias(User $user): string
60	    {
61	        // Deterministic: same user always gets the same alias
62	        $hash = hash_hmac('sha256', (string) $user->id, config('app.key', 'civiccrowd-salt'));
63	        $suffix = substr($hash, 0, 8);
64	
65	        return 'Reviewer-' . $suffix;
66	    }
