11	class SetLocale
12	{
13	    public function handle(Request $request, Closure $next): Response
14	    {
15	        $locale = $this->resolveLocale($request);
16	        App::setLocale($locale);
17	        Carbon::setLocale($locale);
18	
19	        $user = $request->user();
20	
21	        if ($user && $user->timezone) {
22	            date_default_timezone_set($user->timezone);
23	            Carbon::setLocale($locale);
24	        }
25	
26	        return $next($request);
27	    }
28	
29	    private function resolveLocale(Request $request): string
30	    {
31	        $user = $request->user();
32	
33	        if ($user && $user->locale) {
34	            return $user->locale;
35	        }
36	
37	        $acceptLanguage = $request->header('Accept-Language');
38	
39	        if ($acceptLanguage) {
40	            $locale = $this->parseAcceptLanguage($acceptLanguage);
41	
42	            if ($locale) {
43	                return $locale;
44	            }
45	        }
46	
47	        return config('app.locale', 'en');
48	    }
49	
50	    private function parseAcceptLanguage(string $header): ?string
51	    {
52	        $parts = explode(',', $header);
53	        $firstPart = trim($parts[0]);
54	
55	        $locale = explode(';', $firstPart)[0];
56	        $locale = str_replace('-', '_', trim($locale));
57	
58	        if (! empty($locale)) {
59	            return $locale;
60	        }
61	
62	        return null;
63	    }
64	}
