5	use App\Enums\OrderStatus;
6	use App\Enums\OrderType;
7	use App\Events\BookingConfirmed;
8	use App\Models\Campaign;
9	use App\Models\Order;
10	use App\Models\SeatLock;
11	use App\Models\VenueProgram;
12	use Illuminate\Support\Facades\DB;
13	use Illuminate\Support\Str;
14	use RuntimeException;
15	
16	class BookingService
17	{
18	    public function __construct(
19	        private readonly SeatLockService $seatLockService,
20	    ) {}
21	
22	    public function confirm(SeatLock $lock, array $data): Order
23	    {
24	        return DB::transaction(function () use ($lock, $data) {
25	            $lock->refresh();
26	
27	            if (! $this->seatLockService->isValid($lock)) {
28	                throw new RuntimeException('Seat lock is no longer valid.');
29	            }
30	
31	            $timeSlot = $lock->timeSlot;
32	            $requestKey = $data['request_key'] ?? Str::uuid()->toString();
33	
34	            // Check for idempotent request
35	            $existing = Order::where('request_key', $requestKey)->first();
36	            if ($existing) {
37	                return $existing;
38	            }
39	
40	            // Determine amount from reward tier if not explicitly provided
41	            $amount = $data['amount'] ?? 0;
42	            if ($amount <= 0 && $timeSlot->programable_type === Campaign::class) {
43	                $campaign = Campaign::find($timeSlot->programable_id);
44	                if ($campaign) {
45	                    $tier = $campaign->rewardTiers()->orderBy('price')->first();
46	                    if ($tier && $tier->price > 0) {
47	                        $amount = $tier->price;
48	                    }
49	                }
50	            }
51	
52	            // Determine related campaign/program
53	            $campaignId = null;
54	            $venueProgramId = null;
55	            if ($timeSlot->programable_type === Campaign::class) {
56	                $campaignId = $timeSlot->programable_id;
57	            } elseif ($timeSlot->programable_type === VenueProgram::class) {
58	                $venueProgramId = $timeSlot->programable_id;
59	            }
60	
61	            $order = Order::create([
62	                'user_id' => $lock->user_id,
63	                'campaign_id' => $campaignId,
64	                'venue_program_id' => $venueProgramId,
65	                'time_slot_id' => $timeSlot->id,
66	                'request_key' => $requestKey,
67	                'confirmation_number' => $this->generateConfirmationNumber(),
68	                'order_type' => OrderType::Reservation,
69	                'seat_quantity' => $lock->quantity,
70	                'amount' => $amount,
71	                'currency' => $data['currency'] ?? 'USD',
72	                'status' => OrderStatus::Confirmed,
73	            ]);
74	
75	            $timeSlot->increment('seats_booked', $lock->quantity);
76	
77	            $this->seatLockService->release($lock);
78	
79	            BookingConfirmed::dispatch($order, $lock);
80	
81	            return $order;
82	        });
83	    }
84	
85	    public function generateConfirmationNumber(): string
86	    {
87	        $datePart = now()->format('ymd');
88	        $randomPart = strtoupper(Str::random(8));
89	
90	        return "CC-{$datePart}-{$randomPart}";
91	    }
92	}
